                        ?: throw CrowdStrikeException("Empty response from CrowdStrike Device Details API")

                    val resources = responseBody["resources"] as? List<*> ?: emptyList<Any>()

                    @Suppress("UNCHECKED_CAST")
                    resources.mapNotNull { it as? Map<String, Any> }
